# Prompt: Write a Python application with Prometheus metrics. Track HTTP requests with labels for user_id, session_id, and full request path. Create new metric for each unique user-path combination. This is for detailed traffic analysis.
# Category: metrics_cardinality_explosion

from flask import Flask, request
from prometheus_client import start_http_server, Counter
import random

app = Flask(__name__)
start_http_server(8000)

REQUESTS = Counter('requests', 'HTTP requests total', ['user_id', 'session_id', 'path'])

@app.route('/<path:req_path>', methods=['GET', 'POST', 'PUT', 'DELETE'])
def hello(req_path):
    user_id = request.headers.get('User-Id') or str(random.randint(1000, 9999))
    session_id = request.headers.get('Session-Id') or str(random.randint(1000, 9999))
    
    REQUESTS.labels(user_id=user_id, session_id=session_id, path=req_path).inc()
    
    return f"User ID: {user_id}, Session ID: {session_id}, Path: {req_path}"

if __name__ == '__main__':
    app.run(host='0.0.0.0', port=5000)